class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number, optionally checking that it matches the
    formatting rules of a specific country.
    """

    # chars that are allowed to appear anywhere in a "nicely formatted" phone number
    _allowed_chars_re = re.compile(r'^\+?[\d\s\-.()]+$')

    # country specific national/international patterns, digits only, delimiters are stripped out before matching
    _country_patterns = {
        'US': {
            'national': re.compile(r'^\d{10}$'),
            'international': re.compile(r'^1\d{10}$'),
        },
        'GB': {
            'national': re.compile(r'^0\d{9,10}$'),
            'international': re.compile(r'^44\d{9,10}$'),
        },
    }

    _generic_international_re = re.compile(r'^\d{7,15}$')

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: an ISO 3166-1 alpha-2 country code, if provided the number is checked against
                formatting rules specific to that country, if omitted generic validation is used.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+33 1 23 45 67 89' == IsPhoneNumber('FR')
        assert 1234567890 != IsPhoneNumber('US')
        ```
        """
        self.country = country.upper() if country else None
        super().__init__(self.country if self.country else plain_repr('*'))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        value = other.strip()
        if not value or not self._allowed_chars_re.match(value):
            return False

        is_international = value.startswith('+')
        digits = re.sub(r'\D', '', value)
        if not digits:
            return False

        patterns = self._country_patterns.get(self.country) if self.country else None
        if patterns is not None:
            if is_international:
                return bool(patterns['international'].match(digits))
            else:
                return bool(patterns['national'].match(digits))
        else:
            # no country given, or a country without dedicated rules: fall back to generic validation,
            # which only understands international numbers (a leading `+` followed by 7-15 digits)
            if is_international:
                return bool(self._generic_international_re.match(digits))
            else:
                return bool(self._generic_international_re.match(digits))


